def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1.0:
            score = 0.0
        elif ratio > 0.95:
            score = max(0, (1 - ratio)**4 + 0.15)
        elif 0.75 < ratio <= 0.95:
            score = np.exp(-(ratio * 15)) + 0.05
        elif 0.4 < ratio <= 0.75:
            sum_series = 0.0
            for k in range(1, 8):
                term = ((-1) ** k) * (ratio ** (k + 2)) / (k * 2)
                sum_series += term
            score = abs(sum_series) + 0.1
        else:
            polynomial = 0.0
            powers = [3, 5, 7]
            coeffs = [0.2, -0.15, 0.1]
            for p, c in zip(powers, coeffs):
                polynomial += c * (ratio ** p)
            score = max(abs(polynomial), 0.05)
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.1
        capacity_factor = np.cbrt(capacity) + 0.1
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    for i in range(n):
        if priorities[i] < max_finite * 0.2:
            priorities[i] *= 1.2
        elif priorities[i] > max_finite * 3:
            priorities[i] = max_finite * 3
    return priorities
